import ast
import re
from pathlib import Path

import pytest

AC_UID = "baed0fa6365ef6dd"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
CP_CHECKIN = REPO_ROOT / "hooks" / "pretool-cp-checkin.py"
PROMPT_WF = REPO_ROOT / "hooks" / "prompt-workflow.py"
DEV_MD = REPO_ROOT / "commands" / "dev.md"


def _find_assigned_collection(tree: ast.AST, name: str):
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == name:
                    return node.value
    return None


def test_AC_02():
    """
    GIVEN: hooks/pretool-cp-checkin.py, hooks/prompt-workflow.py, commands/dev.md are read as text
    WHEN:  the CP_AGENTS set, agent_types list, and the fallback `for agent in ... ; do` loop are inspected with literal-membership (not substring) semantics
    THEN:  all three sites contain 'test-writer' as a literal Python set/list member or as a literal shell-word token in the for-loop wordlist (NOT as a comment or substring like 'not-test-writer')
    """
    assert CP_CHECKIN.is_file(), f"missing: {CP_CHECKIN}"
    cp_tree = ast.parse(CP_CHECKIN.read_text(encoding="utf-8"))
    cp_agents = _find_assigned_collection(cp_tree, "CP_AGENTS")
    assert cp_agents is not None, "hooks/pretool-cp-checkin.py has no CP_AGENTS assignment"
    cp_members = {e.value for e in ast.walk(cp_agents) if isinstance(e, ast.Constant) and isinstance(e.value, str)}
    assert "test-writer" in cp_members, (
        f"CP_AGENTS in hooks/pretool-cp-checkin.py missing literal 'test-writer' (have: {sorted(cp_members)})"
    )

    assert PROMPT_WF.is_file(), f"missing: {PROMPT_WF}"
    pw_tree = ast.parse(PROMPT_WF.read_text(encoding="utf-8"))
    agent_types = _find_assigned_collection(pw_tree, "agent_types")
    assert agent_types is not None, "hooks/prompt-workflow.py has no agent_types assignment"
    at_members = {e.value for e in ast.walk(agent_types) if isinstance(e, ast.Constant) and isinstance(e.value, str)}
    assert "test-writer" in at_members, (
        f"agent_types in hooks/prompt-workflow.py missing literal 'test-writer' (have: {sorted(at_members)})"
    )

    assert DEV_MD.is_file(), f"missing: {DEV_MD}"
    dev_src = DEV_MD.read_text(encoding="utf-8")
    # Find any 'for agent in ...; do' block, then check its wordlist contains
    # the bare token 'test-writer' (stripping shell comments first).
    m = re.search(r"for\s+agent\s+in\s+([\s\S]*?)\bdo\b", dev_src)
    assert m, "commands/dev.md missing 'for agent in ... ; do' loop"
    wordlist = re.sub(r"#[^\n]*", "", m.group(1))  # strip shell comments
    tokens = re.split(r"[\s;\\]+", wordlist)
    assert "test-writer" in tokens, (
        f"commands/dev.md 'for agent in' wordlist missing bare token 'test-writer' (tokens: {tokens})"
    )
